using Microsoft.ML;
using Microsoft.ML.Data;
using ChurnPredictor;

var builder = WebApplication.CreateBuilder(args);

// Train the model at startup and save it
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
IDataView dataView = mlContext.Data.LoadFromTextFile<ChurnInput>(dataPath, hasHeader: true, separatorChar: ',');

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region))
    .Append(mlContext.Transforms.Concatenate("Features", nameof(ChurnInput.Age), nameof(ChurnInput.Income), "RegionEncoded", nameof(ChurnInput.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: nameof(ChurnInput.Churned), featureColumnName: "Features"));

var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);
var model = pipeline.Fit(split.TrainSet);

var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: nameof(ChurnInput.Churned));
Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, F1: {metrics.F1Score:F4}, Accuracy: {metrics.Accuracy:F4}");

var modelPath = Path.Combine(AppContext.BaseDirectory, "churn_model.zip");
mlContext.Model.Save(model, dataView.Schema, modelPath);

// Register pooled prediction engine (thread-safe for ASP.NET Core)
builder.Services.AddPredictionEnginePool<ChurnInput, ChurnOutput>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with Age, Income, Region, PurchaseHistory");

app.MapPost("/predict", (PredictionEnginePool<ChurnInput, ChurnOutput> pool, ChurnRequest request) =>
{
    var input = new ChurnInput
    {
        Age = request.Age,
        Income = request.Income,
        Region = request.Region,
        PurchaseHistory = request.PurchaseHistory,
    };

    var prediction = pool.Predict(input);

    return Results.Ok(new
    {
        WillChurn = prediction.PredictedLabel,
        Probability = prediction.Probability,
        Score = prediction.Score,
    });
});

app.Run();

namespace ChurnPredictor
